results = []


for item in items:
    item_code = item.get("item_code")
    not_yet_issued = float(item.get("not_yet_issued", 0))
    source_warehouse = item.get("source_warehouse")
    posting_time = frappe.utils.get_datetime(item.get("posting_time"))

    frappe.log_error(
        message=f"Processing item_code: {item_code}, not_yet_issued: {not_yet_issued}, source_warehouse: {source_warehouse}, posting_time: {posting_time}",
        title="Check Item Data"
    )


    # Lấy bin_data
    bin_data = frappe.db.get_value(
    "Bin",
    filters={"item_code": item_code, "warehouse": source_warehouse},
    fieldname=["item_code", "warehouse", "actual_qty", "modified"],
    as_dict=True
    )

    if not bin_data:
        results.append({
            "message": "No Bin data found",
            "item_code": item_code,
            "warehouse": source_warehouse,
        })
        continue

    actual_qty = bin_data.actual_qty
    modified = bin_data.modified

    if posting_time >= modified:
        final_qty = actual_qty
    else:
        # Tính lại tồn kho trong khoảng thời gian
        se_items = frappe.get_all(
            "Stock Entry Detail",
            filters={
                "item_code": item_code,
                "parenttype": "Stock Entry",
                "docstatus": 1,
                "modified": ["between", [posting_time.date(), modified.date()]],
                "s_warehouse": ["in", [source_warehouse, None]],
            },
            fields=["qty", "t_warehouse", "s_warehouse", "parent"]
        )

        adjusted_qty = actual_qty

        for se in se_items:
            if se["t_warehouse"] == source_warehouse:
                adjusted_qty += se["qty"]
            elif se["s_warehouse"] == source_warehouse:
                adjusted_qty -= se["qty"]

        final_qty = adjusted_qty

    if not_yet_issued > final_qty:
        shortage_qty = not_yet_issued - final_qty
        results.append({
            "item_code": item_code,
            "warehouse": source_warehouse,
            "available_qty": final_qty,
            "required_qty": not_yet_issued,
            "shortage_qty": shortage_qty,
            "message": f"Insufficient stock for item '{item_code}' in warehouse '{source_warehouse}'. Shortage: {shortage_qty}. Please prioritize Work Orders."
        })
    else:
        results.append({
            "message": "OK",
            "item_code": item_code,
            "available_qty": final_qty
            })

frappe.response["message"] = results

