def create_employee_checkin(employee_code, employee_name, time, log_type, device_id=None):
    try:
        doc = frappe.db.sql(
            """
            SELECT name
            FROM `tabEmployee Checkin`
            WHERE employee = %s
              AND log_type = %s
              AND DATE(time) = DATE(%s)
            LIMIT 1
            """,
            (employee_code, log_type, time),
            as_dict=True
        )
    
        if doc:
            frappe.db.set_value(
                "Employee Checkin",
                doc[0].name,
                {
                    "time": time,
                    "device_id": device_id,
                    "employee_name": employee_name,
                    "offshift": 0,
                    "skip_auto_attendance": 1
                }
            )
        else:
            doc = frappe.get_doc({
                "doctype": "Employee Checkin",
                "employee": employee_code,
                "employee_name": employee_name,
                "time": time,
                "log_type": log_type,
                "device_id": device_id,
                "offshift": 0,
                "skip_auto_attendance": 1
            })
            doc.insert(ignore_permissions=True)
    except Exception as e:
        frappe.log_error(str(e), "Create Employee Checkin Error")
        return None

