def get_required_materials_from_work_orders(work_orders):
    if isinstance(work_orders, str):
        work_orders = frappe.parse_json(work_orders)

    if not work_orders:
        return []

    materials = {}

    for wo in work_orders:
        bom_items = frappe.get_all(
            "Work Order Item",
            filters={"parent": wo},
            fields=["item_code", "required_qty", "uom"]
        )
        for item in bom_items:
            key = (item["item_code"], item["uom"])
            if key not in materials:
                materials[key] = 0
            materials[key] = materials[key] + item["required_qty"]

    return [
        {
            "item_code": key[0],
            "uom": key[1],
            "total_qty": qty
        }
        for key, qty in materials.items()
    ]

