        SELECT shift_type
        FROM `tabShift Assignment`
        WHERE employee = %s
          AND status = 'Active'
          AND start_date <= %s
          AND (end_date IS NULL OR end_date = '' OR end_date >= %s)
        ORDER BY start_date DESC
        LIMIT 1
    """, (employee, date, date))

    if result:
        return result[0][0]

    return frappe.db.get_value("Employee", employee, "default_shift")


